var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그럼 키이라를 데리고 지원하러 가도록 하겠습니다.","JPN":"では、キーラを連れて支援に向かいます。","ENG":"Then we'll head out with Kiera and provide support.","TWN":"那麼我會帶琪伊拉一起前往支援。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"제일 빠른 운송기를 이용한다면… 약 1시간 41분 49초 정도가 걸리겠네요.","JPN":"もっとも早い輸送機を利用すると……約1時間41分49秒ほどかかりそうですね。","ENG":"If we use the fastest transport... it'll take about 1 hour, 41 minutes, and 49 seconds.","TWN":"使用最快的運輸機……大約需要1小時41分鐘49秒。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"사람들의 목숨이 걸린 일이니 최대한 신속하게 이동해줘.","JPN":"人々の命がかかっていることだ、なるべく早く移動してくれ。","ENG":"Lives are at stake, so move as quickly as possible.","TWN":"好。這攸關人命，盡量迅速前往。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그래, 알파트릭스에서 이 상황에서 차원 도약 허가 요청을 했다고?","JPN":"それで。この状況で、アルファトリックスから次元跳躍の許可を要請してきたと？","ENG":"Right, Alphatrix requested dimension jump clearance in this situation?","TWN":"對了，聽說阿爾法崔克斯那邊要求在這個情況下進行次元跳躍？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그렇습니다.","JPN":"はい。","ENG":"Yes, sir.","TWN":"沒錯。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"규모가 꽤 큰… 팩토리 쉽이라고 하네요.","JPN":"規模の大きい……ファクトリーシップだそうです。","ENG":"They say it's a large-scale... Factory Ship.","TWN":"規模非常龐大……好像是某種工廠艦。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"팩토리 쉽?","JPN":"ファクトリーシップ？","ENG":"Factory Ship?","TWN":"工廠艦？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫, 살면서 한 번이나 볼까 말까 한 걸 다 보게 생겼군.","JPN":"ハハ、これは貴重な物が見れそうだな。","ENG":"Haha, I never thought I'd see one of those in my lifetime.","TWN":"哈哈，今天要長見識，看到這輩子很難看到一次的東西了。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"관리국 본부 주변의 항공기와 함선을 전부 다른 곳으로 배치해 주게.","JPN":"管理局本部周辺の航空機と艦船を全部他の場所に配置してくれ。","ENG":"Move all nearby aircraft and ships away from the Administration HQ.","TWN":"把管理局總部附近的飛機與艦船全部調往其他地方。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"과연, 소문으로만 듣던 함선이 얼마나 거대한지 기대되는구만.","JPN":"どれ、噂の艦船がどれほど巨大なのか楽しみだ。","ENG":"I'm eager to see just how massive that legendary ship really is.","TWN":"讓我也期待一下傳聞中的艦船到底有多巨大吧。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"차원 도약 신호 포착!","JPN":"次元跳躍の信号を捕捉！","ENG":"Dimension jump signal detected!","TWN":"偵測到次元跳躍訊號！"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"엑세스 허가! 함선이 프론트 베이로 진입합니다!","JPN":"アクセス許可！　艦船がフロントベイに進入します！","ENG":"Access approved! The ship is entering Front Bay!","TWN":"允許進入！艦船正進入前灣！"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"저게…….","JPN":"あれが……","ENG":"That's...","TWN":"那個是……"},"stage":{"bg":"SKY","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"에이버리. 이곳은 너무 위험해.","JPN":"エイバリー。ここは危険すぎる。","ENG":"Avery. It's too dangerous here.","TWN":"艾維利，這裡太危險了。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"이 우주선인지 뭔지 모를 것이 우릴 구해줄 수단이라고 하더라도…….","JPN":"この宇宙船だか何だか分からないものが私たちを救ってくれる手段だとしても……","ENG":"Even if this spaceship or whatever it is could save us...","TWN":"就算那不知道是飛船還是什麼的東西能救我們……"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BONNY_NPC_NULL_SILHOUETTE","text":{"KOREA":"하지만 사람이 위험하다는데 꼬리를 말고 도망가자는 거야?!","JPN":"フロントベイのみんなが危険に晒されているのに尻尾を巻いて逃げようっていうのか！？","ENG":"But someone's in danger, and you're telling me we should tuck our tails and run?!","TWN":"可是明明有人遇到危險，你卻要我夾著尾巴逃走？！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BONNY_NPC_NULL_SILHOUETTE","text":{"KOREA":"지푸라기라도 잡는 심정으로 우리는 여기에 온 거잖아.","JPN":"私たちは藁にもすがる思いでここに来たんじゃないか。","ENG":"We came here clinging to even the slightest hope, didn't we?!","TWN":"我們是抱著抓住最後一根稻草的心情來到這裡的。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"BONNY_NPC_NULL_SILHOUETTE","text":{"KOREA":"다들 죽거나 다치는 것쯤은 각오하고 왔어!","JPN":"死ぬことや怪我することくらい、覚悟の上だ！","ENG":"We knew people might die or get hurt coming in!","TWN":"大家都有覺悟可能會死、會受傷！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"현실적으로 생각해 보자는 거란다. 보니.","JPN":"現実的に考えようと言っているのよ、ボニー。","ENG":"Try to think realistically, Bonny.","TWN":"妳冷靜想想，寶妮。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"에이버리나, 너나 사람을 구해야겠다는 마음은 이해하지만, 이건 너무 위험해.","JPN":"エイバリーもあなたも、人を救いたい気持ちはわかるけど、これは危険すぎる。","ENG":"I know you and Avery both want to save people, but this is far too dangerous.","TWN":"艾維利，你、還有我，想救人的心情我懂，但現在太危險了。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"이미 이곳까지 오는 길에도 많은 선원들이 다쳤잖니?","JPN":"ここに来るまでもたくさんの船員が怪我をしたじゃない。","ENG":"Many of our crew were injured just getting here.","TWN":"光是到這裡的路上，就已有不少船員受傷。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"우리마저 이곳에서 모두 죽으면, 그때 육지의 사람들은 누가 지켜줘?","JPN":"私たちまでここ全滅してしまったら、陸の人たちを誰が守るの？","ENG":"If we all die in this place, who will protect the people on land?","TWN":"如果我們也全死在這裡，那誰來保護陸地上的人？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"그렇기 때문에 물러설 수 없는 거야, 리드.","JPN":"だからこそ引き下がれないんだ、リード。","ENG":"And that's exactly why we can't retreat, Read.","TWN":"正因為如此我們才不能退縮，里德。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"우리는 저 희생을 딛고 어떻게든 검은 범람을 이겨낼 방법을 찾아내야만 해.","JPN":"私たちは彼らの犠牲を乗り越えて、どうにかして黒い氾濫を克服する方法を見つけなければならない。","ENG":"We have to stand on the sacrifices already made and find a way to overcome the Black Flood.","TWN":"我們得踏過那些犧牲的人，無論如何都要找出戰勝黑色洪災的方法。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};